import scala.collection.immutable.List

object Solution {
  def events(events: Array[String]): Array[Long] = {
    var score: Long = 0
    var counter: Int = 0

    for (event <- events) {
      // Check termination condition
      if (counter >= 10) {
        break
      }

      event match {
        case "0" | "1" | "2" | "3" | "4" | "6" =>
          score += event.toInt
        case "W" =>
          counter += 1
        case "WD" =>
          score += 1
        case "NB" =>
          score += 1
        case _ =>
          // Should not happen based on problem description
      }
    }

    // Final check for counter reaching 10 after processing the last element that might have incremented it
    if (counter == 10 && events.length > 0) {
        // If the last event caused counter to hit 10, we stop, and the loop handles the break condition at the start of the *next* iteration.
        // If the loop finishes naturally, we return the accumulated values.
    }

    Array(score, counter.toLong)
  }
}
